var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"이상으로, 보고를 마치겠습니다.","JPN":"報告は以上です。","ENG":"That concludes my briefing.","TWN":"以上就是報告的全部內容。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"좋아. 이제 조직도가 얼추 맞아떨어졌고, 놈들의 행동반경과 패턴도 어느 정도 파악됐으니……","JPN":"よし。組織図もそろそろ見えてきたし、やつらの行動半径とパータンもそれなりに把握できたから……","ENG":"All right. Looks like we got those perps all mapped out and what their daily schedule is like…","TWN":"很好。現在組織結構大致對上了，敵人的活動範圍和模式也已經掌握了…"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"이제 기회를 봐서 일망타진하는 일만 남았군.","JPN":"あとは、機会を見て一網打尽するだけだな。","ENG":"Now, we just wait for the right timing to strike.","TWN":"現在就剩下找機會一網打盡了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"네, 아시다시피 두 조직은 치안이 빈약한 빈민가에서 활동하기 때문에 아주 대범하게 움직이고 있습니다.","JPN":"はい。ご存じの通り、両組織は治安が悪いスラム街で活動しているため、とても大胆に動いています。","ENG":"As you know, the two families are stationed in the slums, and have been boldly active.","TWN":"是的，這兩個組織經常在治安較差的貧民區活動，所以行動非常大膽。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"게다가 지금은 양측 모두 얼마 전 도시에 나타난 위저드라는 신흥 세력을 견제하는 중입니다.","JPN":"それに今は両方とも、この前から都市に現われたウィザードという新興勢力を牽制しているところです。","ENG":"Also, reports say that the two are currently busy trying to maintain their territory against the newly formed ”Wizard\\".","TWN":"而且現在雙方都在牽制城市裡的新興勢力——巫師。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"지금의 규모로는 각개격파 당할 가능성이 높기 때문에 조만간 한쪽을 흡수하려고 전면전을 벌일 겁니다.","JPN":"現在の規模では各個撃破される可能性が高いので、そのうち片方を吸収しようと全面戦争をするでしょう。","ENG":"Both seem to be outnumbered, so one side will try to take over the other sometime soon.","TWN":"以現在的規模來看，很容易被逐個擊破，所以不久後他們會發動全面戰爭，試圖吞併一方。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"놈들이 그 위저드란 놈들 때문에 서로 협력할 가능성은?","JPN":"やつらがそのウィザードという連中のせいで手を組む可能性は？","ENG":"What’s the probability of them joining forces to fight against that “Wizard\\"?","TWN":"你覺得他們會因為對付巫師而互相合作嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"원래부터 이권다툼이 심했고 심심찮게 마찰이 있어왔던 관계입니다. 지금까지의 양상으로 볼 때 그런 생각을 할 만한 브레인은 내부에 없습니다.","JPN":"元々争いが頻繁に起きていた仲です。今までの構図を踏まえると、そんなことを考えるブレーンは内部に存在しません。","ENG":"They've been at odds over territory for a long time. Furthermore, based on what has occurred thus far, neither family has anyone with the intellect to reach such an agreement.","TWN":"原本他們之間有很大的利益衝突，時不時就有摩擦。但從目前的情況來看，內部沒有人會有那樣的想法。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"그림 좋네. 알아보느라 고생 많았어.","JPN":"結構だ。調査、ご苦労だったぞ。","ENG":"I like the sound of that. Good work, officer.","TWN":"調查得不錯，辛苦你了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"하지만 진압조를 움직이려면 확실한 근거가 필요해. 좀 더 조사해볼 필요가 있어.","JPN":"だが、鎮圧組を動くには確かな根拠が必要だ。もう少し調査する必要がある。","ENG":"But we need concrete evidence to send in the striking force. We need someone to keep digging.","TWN":"但是動用鎮壓隊需要確切的證據，所以還要進一步調查。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"그쪽 관할구에서 뒷말 안 나오게 하려면 확실하게 물증 잡고 쳐야 돼.","JPN":"そちらの管轄区域で不満が出ないようにするためには、確実な物証を確保しないといけない。","ENG":"If we don’t want any backlash from that jurisdiction, we need to have irrefutable evidence.","TWN":"要想在那邊的管轄區內不留下後患，就必須得到確切的證據再動手。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"내 말, 무슨 말인지 알겠지?","JPN":"私の話、わかるだろう？","ENG":"Do you understand my words?","TWN":"你明白我說的話吧？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"물론입니다. 그렇게 하겠습니다.","JPN":"もちろんです。そうします。","ENG":"Of course, sir. I’ll get right on it.","TWN":"明白，我立刻去辦。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"휴우… 시작부터 끝까지 뒤치다꺼리는 다 내 몫이구만.","JPN":"ふう……最初から最後まで後片付けは全部俺の分だな。","ENG":"Whew... Guess this one’s just me, myself, and I...","TWN":"呼…從頭到尾全都是我在做事。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"난 세상의 안위를 지키고 있는데 내 주말은 누가 지켜주나?","JPN":"俺は世界の平和を守ってるんだけど、俺の週末は誰が守ってくれるんだ？","ENG":"Here I am looking after the world, but who’s looking after my weekend?","TWN":"我在守護世界的安危，那誰來守護我的週末呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"……음?","JPN":"……む？","ENG":"...Mm?","TWN":"…嗯？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"아주 호되게 당했군.","JPN":"めちゃくちゃにやられてるな。","ENG":"Whoa... They got you good.","TWN":"下手還真狠毒。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"아직 숨은 붙어있는 것 같은데?","JPN":"まだ息はしてるみたいだぞ？","ENG":"Wait... I think he’s still breathing.","TWN":"看起來好像還有呼吸？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"으으……","JPN":"うう……","ENG":"Ugh...","TWN":"呃呃…"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"거기, 무슨 일이 있었던 겁니까?","JPN":"そこ、何かあったんですか？","ENG":"Hey! What’s going on over there?","TWN":"喂，發生了什麼事嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"넘어오지 말고 물러서세요. 일반인은 들어오시면 안 됩니다.","JPN":"近づかないで、下がってください。一般人は立ち入り禁止です。","ENG":"Please step back, sir. Authorized personnel only.","TWN":"不要靠近，請退後。非相關人員請不要靠近。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"……전 경찰청 강력계 형사, 강민우입니다.","JPN":"……俺は警察庁の捜査課刑事、マツダ・シュウイチです。","ENG":"...I’m a homicide detective, Kang Minwoo, from the police.","TWN":"…我是重案組刑警，姜民宇。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"……이쪽 관할이 아니신데, 여기까진 어쩐 일로 오셨죠?","JPN":"……こちらの管轄ではないはずなのに、どうしてここまで？","ENG":"...This isn’t your jurisdiction. What brings you here, sir?","TWN":"…這不是你的轄區，你怎麼會到這裡來？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"미안합니다. 그 부분은 대외비라서요.","JPN":"すみません。そこは極秘なんで。","ENG":"Sorry. That’s classified.","TWN":"對不起，這是機密，無可奉告。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"그나저나, 여기 무슨 싸움이라도 났던 겁니까?","JPN":"ところで、ここで何かケンカでもあったんですか？","ENG":"Anyway, what happened here?","TWN":"不過，這裡是發生了什麼火拼嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"별거 아닙니다.","JPN":"大したことじゃないです。","ENG":"It's probably nothing.","TWN":"沒什麼大不了的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};